+function normalizeOllamaToolCallName(rawName: string): string {
+  const trimmed = rawName.trim();
+  if (!trimmed) {
+    return trimmed;
+  }
+  return trimmed.replace(/^(?:functions?|tools?)[./_-]+/iu, "").trim();
+}
